import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.util.Scanner;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize and escape user input before outputting it to the webpage
        String sanitizedInput = "";
        try {
            sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);
            System.out.println("<p>Welcome, " + sanitizedInput + "!</p>");
        } catch (EncodingException e) {
            System.out.println("Error sanitizing user input.");
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
